import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, LinearProgress } from '@mui/material';
import { CircularProgress } from '@mui/material';
import response from './response.json';

interface Task {
  task: string;
  priority: string;
  completed: boolean;
}

interface TaskManagerData {
  todayTasks: Task[];
  completionProgress: number;
}

export default function Widget() {
  const taskManagerData = response.data.data as TaskManagerData;
  const { todayTasks, completionProgress } = taskManagerData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2B2B2B' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="#FFC107" fontWeight={600}>
              Task Manager Pro
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Today's Tasks
            </Typography>
          </Box>

          <Stack spacing={1}>
            {todayTasks.slice(0, 3).map((task, index) => (
              <Box key={index} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Typography
                  variant="body2"
                  sx={{ textDecoration: task.completed ? 'line-through' : 'none', color: '#FFFFFF' }}
                >
                  {task.task}
                </Typography>
                <Chip
                  label={task.priority}
                  sx={{
                    fontSize: '10px',
                    bgcolor: task.priority === 'High' ? '#FF5722' : task.priority === 'Medium' ? '#FFC107' : '#757575',
                    color: '#FFFFFF'
                  }}
                  size="small"
                />
              </Box>
            ))}
          </Stack>

          <Box>
            <Typography variant="caption" color="text.secondary">
              Completion Progress
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center', mt: 1 }}>
              <CircularProgress variant="determinate" value={completionProgress} size={40} sx={{ color: '#FF5722' }} />
              <Typography variant="body2" sx={{ ml: 1, color: '#FFFFFF' }}>
                {completionProgress}%
              </Typography>
            </Box>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
